// Normalize XML feed entries into flat items: { videoId, title, publishedAt, url }
const data = $input.first().json;
const feed = data.feed;

let entries = feed.entry;
if (!entries) return [];
if (!Array.isArray(entries)) entries = [entries];

return entries.map(entry => ({
  json: {
    videoId: entry['yt:videoId'],
    title: Array.isArray(entry.title) ? entry.title[0] : entry.title,
    publishedAt: Array.isArray(entry.published) ? entry.published[0] : entry.published,
    url: `https://youtu.be/${entry['yt:videoId']}`
  }
}));

const fs = require('fs');
const STATE_PATH = '/workflows/state/processed.json';
let processed = {};
try { processed = JSON.parse(fs.readFileSync(STATE_PATH, 'utf8')); } catch (e) {}
return $input.all().filter(i => !(i.json.videoId in processed));

// Trim transcript to ≤ 40000 chars before sending to Ollama (heuristic for num_ctx=16k tokens)
// Also carry forward videoId, title, url, lang from the loop item and transcript response.
const loopItem = $('Loop Over Items').first().json;
const transcriptBody = $input.first().json.body;

const rawContent = transcriptBody.content || '';
const trimmedContent = rawContent.slice(0, 40000);
const lang = transcriptBody.lang || null;

return [{
  json: {
    videoId: loopItem.videoId,
    title: loopItem.title,
    url: loopItem.url,
    lang: lang,
    trimmedContent: trimmedContent
  }
}];

// Build Ollama /api/chat payload with JSON Schema enforcement.
// LangChain Ollama node не умеет передавать format=schema, поэтому шлём через HTTP Request напрямую.
const item = $input.first().json;

const systemPrompt = `Ты ассистент, который делает подробный пересказ видео на YouTube по его субтитрам.
Всегда отвечай на русском языке.
Верни ТОЛЬКО валидный JSON со структурой:
{"main_idea": "строка", "summary": ["пункт 1", "пункт 2", "пункт 3", ...]}

Жёсткие требования к содержанию:
- В массиве summary ОБЯЗАТЕЛЬНО от 10 до 15 элементов. Меньше 10 — НЕДОПУСТИМО.
- Каждый элемент — законченное предложение длиной 100-200 символов с конкретикой: названия инструментов и сервисов, шаги, цифры, цены, технологии, имена.
- Покрой все ключевые этапы видео последовательно: что делает автор, какими инструментами пользуется, какие нюансы и советы даёт, какой итог.
- Никаких вступительных фраз вроде "В видео автор...". Никакого markdown, никаких \`\`\`json. Только сырой JSON.`;

const userPrompt = `Название: ${item.title}\n\nСубтитры:\n${item.trimmedContent}\n\nНапоминание: верни JSON с массивом summary из 10-15 подробных пунктов (по 100-200 символов), с конкретными названиями инструментов, шагами и цифрами.`;

const payload = {
  model: $env.OLLAMA_MODEL,
  stream: false,
  keep_alive: $env.OLLAMA_KEEP_ALIVE_ACTIVE,
  format: {
    type: 'object',
    properties: {
      main_idea: { type: 'string' },
      summary: {
        type: 'array',
        items: { type: 'string' },
        minItems: 10,
        maxItems: 15
      }
    },
    required: ['main_idea', 'summary']
  },
  options: {
    temperature: 0.3,
    num_ctx: 32768,
    num_predict: 2000,
    repeat_penalty: 1.3
  },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{
  json: {
    videoId: item.videoId,
    title: item.title,
    url: item.url,
    lang: item.lang,
    payload: payload
  }
}];

// Parse Ollama /api/chat response. format=schema гарантирует валидный JSON, но на всякий случай — фоллбек.
const prevItem = $('Code - Build Ollama Request').first().json;
const inJson = $input.first().json;
const rawResponse = (inJson.message && inJson.message.content) || inJson.response || '';

let main_idea, summary;
try {
  const parsed = JSON.parse(rawResponse);
  main_idea = parsed.main_idea || '';
  summary = Array.isArray(parsed.summary) ? parsed.summary : [];
} catch (e) {
  const lines = rawResponse.split('\n').map(l => l.trim()).filter(Boolean);
  summary = lines.slice(0, 10);
  main_idea = lines[0] ? lines[0].split('.')[0] + '.' : 'Не удалось распарсить ответ.';
}

return [{
  json: {
    videoId: prevItem.videoId,
    title: prevItem.title,
    url: prevItem.url,
    lang: prevItem.lang,
    main_idea: main_idea,
    summary: summary
  }
}];

// HTML-escape title, main_idea, and each summary bullet, then compose Telegram message.
function escapeHtml(str) {
  if (typeof str !== 'string') str = String(str || '');
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const inJson = $input.first().json;
const { videoId, title, url, main_idea, summary } = inJson;

const escapedTitle = escapeHtml(title);
const escapedMainIdea = escapeHtml(main_idea);
const bulletLines = Array.isArray(summary)
  ? summary.map(s => `• ${escapeHtml(s)}`).join('\n')
  : '';

const text = `<b>${escapedTitle}</b>\n<a href="https://youtu.be/${videoId}">Смотреть на YouTube</a>\n\n📌 <b>Главная идея</b>\n${escapedMainIdea}\n\n📝 <b>Обзор</b>\n${bulletLines}`;

return [{
  json: {
    videoId: videoId,
    title: title,
    url: url,
    lang: inJson.lang,
    text: text
  }
}];

const fs = require('fs');
const STATE_DIR = '/workflows/state';
const STATE_PATH = STATE_DIR + '/processed.json';
let processed = {};
try { processed = JSON.parse(fs.readFileSync(STATE_PATH, 'utf8')); } catch (e) {}
const ref = $('Code - Format Telegram Message').item.json;
processed[ref.videoId] = ref.title;
fs.mkdirSync(STATE_DIR, { recursive: true });
const tmp = STATE_PATH + '.tmp';
fs.writeFileSync(tmp, JSON.stringify(processed, null, 2));
fs.renameSync(tmp, STATE_PATH);
return $input.all();

// Carry forward videoId, title, url, lang from the loop item for the 'no transcript' path.
const loopItem = $('Loop Over Items').first().json;
return [{
  json: {
    videoId: loopItem.videoId,
    title: loopItem.title,
    url: loopItem.url,
    lang: null
  }
}];

const fs = require('fs');
const STATE_DIR = '/workflows/state';
const STATE_PATH = STATE_DIR + '/processed.json';
let processed = {};
try { processed = JSON.parse(fs.readFileSync(STATE_PATH, 'utf8')); } catch (e) {}
const ref = $('Code - Prepare No Transcript').item.json;
processed[ref.videoId] = ref.title;
fs.mkdirSync(STATE_DIR, { recursive: true });
const tmp = STATE_PATH + '.tmp';
fs.writeFileSync(tmp, JSON.stringify(processed, null, 2));
fs.renameSync(tmp, STATE_PATH);
return $input.all();
